1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const basePremiumForType = (type: string): number => {
13	  if (!(type in BASE_PREMIUMS)) throw new Error(`Unknown item type: ${type}`);
14	  return BASE_PREMIUMS[type];
15	};
16	
17	const CURSED_SURCHARGE_RATE = 0.5;
18	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT_RATE = 0.2;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
24	
25	const DEDUCTIBLE = 100;
26	const CLAIM_ENCHANTMENT_THRESHOLD = 8;
27	const CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
28	const PAYOUT_CAP_MULTIPLIER = 2;
29	
30	const INSURANCE_VALUES: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const COMPONENT_TYPES = ["rune", "moonstone"];
40	const BLOCK_SIZE = 3;
41	const BLOCK_PREMIUM = 60;
42	
43	const componentPremium = (type: string, count: number): number =>
44	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * basePremiumForType(type);
45	
46	const itemSurcharge = (item: any): number => {
47	  const base = basePremiumForType(item.type);
48	  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
49	    + (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
50	};
51	
52	const countByType = (items: any[]): Record<string, number> =>
53	  items.reduce((counts: Record<string, number>, item: any) => {
54	    counts[item.type] = (counts[item.type] ?? 0) + 1;
55	    return counts;
56	  }, {});
57	
58	const isComponent = (item: any): boolean => COMPONENT_TYPES.includes(item.type);
59	
60	const calculateQuotePremium = (items: any[], customer: any, stepIndex: number): number => {
61	  const regularItems = items.filter((item: any) => !isComponent(item));
62	  const components = items.filter(isComponent);
63	
64	  const regularBasePremium = regularItems.reduce(
65	    (sum, item) => sum + basePremiumForType(item.type), 0);
66	  const componentBasePremium = Object.entries(countByType(components)).reduce(
67	    (sum, [type, count]) => sum + componentPremium(type, count), 0);
68	  const policyBasePremium = regularBasePremium + componentBasePremium;
69	
70	  const totalSurcharges = regularItems.reduce(
71	    (sum, item) => sum + itemSurcharge(item), 0);
72	
73	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
74	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
75	    : 0;
76	  const followUpDiscount = stepIndex > 0 ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
77	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
78	
79	  const premium = policyBasePremium + totalSurcharges - loyaltyDiscount
80	    + firstInsuranceSurcharge - followUpDiscount;
81	  return Math.ceil(premium + PROCESSING_FEE);
82	};
83	
84	const isHighEnchantment = (policyItem: any): boolean =>
85	  policyItem != null && policyItem.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD;
86	
87	const reimbursableAmount = (damage: any, policyItem: any): number =>
88	  isHighEnchantment(policyItem)
89	    ? damage.amount * CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE
90	    : damage.amount;
91	
92	const calculateClaimPayout = (damages: any[], policyItems: any[]): number => {
93	  const insuranceSum = policyItems.reduce(
94	    (sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
95	  const cap = insuranceSum * PAYOUT_CAP_MULTIPLIER;
96	  const uncappedPayout = damages.reduce((payout, damage) => {
97	    const policyItem = policyItems.find((item: any) => item.type === damage.type);
98	    return payout + Math.max(0, reimbursableAmount(damage, policyItem) - DEDUCTIBLE);
99	  }, 0);
100	  return Math.min(uncappedPayout, cap);
101	};
102	
103	export const processScenario = (scenario: any): any => {
104	  let policyItems: any[] = [];
105	  return {
106	    results: scenario.steps.map((step: any, index: number) => {
107	      if (step.op === "claim") {
108	        return { payout: calculateClaimPayout(step.damages, policyItems) };
109	      }
110	      policyItems = step.items;
111	      return { premium: calculateQuotePremium(step.items, scenario.customer, index) };
112	    }),
113	  };
114	};
